final:
module JK_latch (
    input wire obf_J,
    input wire K,
    input wire clk,
    output reg Q
);
    always @(posedge clk) begin
        if (obf_J && !K)
            Q <= 1;
        else if (!obf_J && K)
            Q <= 0;
        else if (obf_J && K)
            Q <= ~Q; // toggle
    end
endmodule
